16	export interface QuoteResult {
17	  basePremium: number;
18	  premium: number;
19	}
20	
21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const PROCESSING_FEE = 5;
31	const BLOCK_OF_THREE_PREMIUM = 60;
32	const LOYALTY_DISCOUNT_RATE = 0.2;
33	const FIRST_INSURANCE_RATE = 0.1;
34	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
35	const CURSE_SURCHARGE_RATE = 0.5;
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
38	
39	function surchargeRateFor(item: Item): number {
40	  let rate = 0;
41	  if (item.cursed) rate += CURSE_SURCHARGE_RATE;
42	  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) rate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
43	  return rate;
44	}
45	
46	function surchargeFor(item: Item): number {
47	  return basePremiumByType[item.type] * surchargeRateFor(item);
48	}
49	
50	function premiumForTypeBlock(type: string, count: number): number {
51	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
52	  return count * basePremiumByType[type];
53	}
54	
55	export function quote(
56	  customer: Customer,
57	  items: Item[],
58	  options: QuoteOptions = {},
59	): QuoteResult {
60	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
61	    counts[item.type] = (counts[item.type] ?? 0) + 1;
62	    return counts;
63	  }, {});
64	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
65	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
66	    0,
67	  );
68	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
69	  const basePremium = baseWithoutSurcharges + surcharges;
70	
71	  let premium = basePremium;
72	  if (customer.yearsWithMHPCO >= 2) premium -= baseWithoutSurcharges * LOYALTY_DISCOUNT_RATE;
73	  if (items.length > 0) premium += baseWithoutSurcharges * FIRST_INSURANCE_RATE;
74	  if (options.followUp) premium -= baseWithoutSurcharges * FOLLOW_UP_DISCOUNT_RATE;
75	  premium = Math.ceil(premium + PROCESSING_FEE);
76	
77	  return { basePremium, premium };
78	}
